export type Category = "morning" | "evening";
export type ThemeMode = "day" | "night";
export type BgColorKey = "white" | "cream" | "mint";

export interface Dhikr {
  id: string;
  text: string;
  maxCount: number;
  currentCount: number;
  category: Category;
  isQuran?: boolean;
}

export interface AppSettings {
  theme: ThemeMode;
  bgColor: BgColorKey;
  fontSize: number;
  notificationsEnabled: boolean;
  morningNotifHour: number;
  morningNotifMinute: number;
  eveningNotifHour: number;
  eveningNotifMinute: number;
}

export interface DailyStats {
  date: string;
  morningCount: number;
  eveningCount: number;
}

export interface CompletionRecord {
  date: string;
  morning: boolean;
  evening: boolean;
}

interface AppContextValue {
  adhkar: Dhikr[];
  settings: AppSettings;
  activeCategory: Category;
  isPlayingAll: boolean;
  recordings: Record<string, string>;
  speakingId: string | null;
  dailyStats: DailyStats;
  setActiveCategory: (cat: Category) => void;
  decrementCount: (id: string) => void;
  resetCategory: (category: Category) => void;
  categoryResetKey: number;
  addDhikr: (text: string, count: number, category: Category) => void;
  editDhikr: (id: string, text: string, count: number) => void;
  deleteDhikr: (id: string) => void;
  updateSettings: (patch: Partial<AppSettings>) => void;
  speakAll: () => void;
  stopSpeaking: () => void;
  speakDhikr: (id: string, text: string, count?: number) => void;
  stopDhikrSpeech: () => void;
  stopAllAudio: () => Promise<void>;
  registerCardSound: (sound: Audio.Sound | null) => void;
  getPlaybackGen: () => number;
  playingCardId: string | null;
  setPlayingCardId: (id: string | null) => void;
  saveRecording: (id: string, uri: string) => void;
  deleteRecording: (id: string) => void;
  scheduleNotifications: (s: AppSettings) => Promise<void>;
  completionHistory: CompletionRecord[];
}

